import{_ as e,o as i,c as a,an as o}from"./chunks/framework.CVlxHKcL.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"MAGEMinApp/PTX_tutorials.md","filePath":"MAGEMinApp/PTX_tutorials.md","lastUpdated":null}'),n={name:"MAGEMinApp/PTX_tutorials.md"};function l(r,t,s,c,p,d){return i(),a("div",null,[...t[0]||(t[0]=[o('<img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/MAGEMinApp_tabs_PTX.png?raw=true" alt="MAGEMinApp tabs" style="max-width:100%;height:auto;display:block;margin:0 auto;"><h2 id="P-T-X-paths-tutorials-MAGEMinApp-v1.2.1" tabindex="-1">P-T-X paths tutorials (MAGEMinApp v1.2.1) <a class="header-anchor" href="#P-T-X-paths-tutorials-MAGEMinApp-v1.2.1" aria-label="Permalink to &quot;P-T-X paths tutorials (MAGEMinApp v1.2.1) {#P-T-X-paths-tutorials-MAGEMinApp-v1.2.1}&quot;">​</a></h2><p>Here we provide a set of tutorials to generate various kind of pressure-temperature-composition paths: including batch melting, fractional melting and fractional crystallization.</p><h3 id="E.1.-Quick-start-first-P-T-X-path" tabindex="-1">E.1. Quick start - first P-T-X path <a class="header-anchor" href="#E.1.-Quick-start-first-P-T-X-path" aria-label="Permalink to &quot;E.1. Quick start - first P-T-X path {#E.1.-Quick-start-first-P-T-X-path}&quot;">​</a></h3><p>For the first P-T-X path, simply launch <code>MAGEMinApp</code> and navigate to the <code>PTX path</code> tab. Change default setting for the thermodynamic database (<code>Igneous</code>)(Green et al., 2025 after Holland et al., 2018) and default bulk-rock composition (<code>KLB1 Peridotite anhydrous</code>). In the <code>Path definition</code> panel click on <code>Find solidus</code> and <code>Find liquidus</code> and define the P-T points accordingly:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_quickstart_setup.png?raw=true" alt="PTX quickstart setup" style="max-width:80%;height:auto;display:block;margin:0 auto;"><div class="tip custom-block"><p class="custom-block-title">Note</p><ul><li><p>New points for the P-T-X path can be added by clicking on <code>Add new point</code>.</p></li><li><p>To delete a point simply click on the cross icon on the left of point.</p></li></ul></div><p>In the <code>Path options</code> panel, change the resolution to 32. This option defines the number of point-wise calculation between two defined points. Hit <code>Compute path</code> and after a few seconds you should get the following result:</p><h4 id="Stable-phase-fraction" tabindex="-1">Stable phase fraction <a class="header-anchor" href="#Stable-phase-fraction" aria-label="Permalink to &quot;Stable phase fraction {#Stable-phase-fraction}&quot;">​</a></h4><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_quickstart_diagram.png?raw=true" alt="PTX quickstart diagram" style="max-width:80%;height:auto;display:block;margin:0 auto;"><h4 id="Stable-phase-composition" tabindex="-1">Stable phase composition <a class="header-anchor" href="#Stable-phase-composition" aria-label="Permalink to &quot;Stable phase composition {#Stable-phase-composition}&quot;">​</a></h4><p>Then in the <code>Phase composition</code> tab, click <code>liq</code> which will display the evolution of the melt composition along the path:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_quickstart_composition.png?raw=true" alt="PTX quickstart composition" style="max-width:80%;height:auto;display:block;margin:0 auto;"><div class="tip custom-block"><p class="custom-block-title">Note</p><ul><li><p>Double-clicking on one ooxide will isolate it.</p></li><li><p>Double-clicking again on the same oxide, will bring back all the oxides.</p></li></ul></div><h4 id="TAS-diagram" tabindex="-1">TAS diagram <a class="header-anchor" href="#TAS-diagram" aria-label="Permalink to &quot;TAS diagram {#TAS-diagram}&quot;">​</a></h4><p>When <code>liq</code> is selected you can access the <code>TAS diagram</code> which displays the evolution of the melt composition (Total Alkali Silica):</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_quickstart_TAS.png?raw=true" alt="PTX quickstart TAS" style="max-width:60%;height:auto;display:block;margin:0 auto;"><div class="warning custom-block"><p class="custom-block-title">Warning</p><ul><li>When computing a new PTX diagram, to refresh the TAS diagram, you need to unselect and reselect <code>liq</code> in the <code>Composition</code> panel.</li></ul></div><h3 id="E.2.-Fractional-melting" tabindex="-1">E.2. Fractional melting <a class="header-anchor" href="#E.2.-Fractional-melting" aria-label="Permalink to &quot;E.2. Fractional melting {#E.2.-Fractional-melting}&quot;">​</a></h3><p>In this example, we are going to perform fractional melting using <code>SM89 oxidized average MORB</code> composition using the <code>Metabasite</code> thermodynamic database (Green et al., 2016). First make sure you select <code>Aug</code> in the clinopyroxene selection, then define the P-T points of the path as follow:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_FM_path.png?raw=true" alt="PTX FM path" style="max-width:80%;height:auto;display:block;margin:0 auto;"><p>In the <code>Path options</code> panel, choose a resolution of 32, and select <code>P-T-X mode = fractional melting</code>, keep <code>Assimiliation = false</code> and <code>Connectivity threshold [%] = 7</code>:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_FM_path_mode.png?raw=true" alt="PTX FM path mode" style="max-width:40%;height:auto;display:block;margin:0 auto;"><div class="tip custom-block"><p class="custom-block-title">Note</p><ul><li><p>The connectivity threshold is the value above which melt is extracted</p></li><li><p>Presently, only the melt above this value is extracted to keep the melt fraction at the connectivity threshold.</p></li><li><p>When computing a fractional melting path using a connectivity threshold, the displayed fraction of melt can be slightly above the threshold as the removed fraction of melt is only applied to the subsequent calculation step. This effect can however be minimized by increasing the resolution.</p></li></ul></div><p>Process with the P-T-X path calculation, which should yield:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_FM_path_diagram.png?raw=true" alt="PTX FM path diagram" style="max-width:80%;height:auto;display:block;margin:0 auto;"><div class="tip custom-block"><p class="custom-block-title">Note</p><ul><li><p>The black continuous line <code>remaining %</code> represents the remaining % with respect to the starting material.</p></li><li><p>The black dashed line <code>removed %</code> is the mass % of material removed with respect to the starting material.</p></li><li><p><code>remaining %</code> + <code>removed %</code> = 100.0</p></li></ul></div><h3 id="E.3.-Fractional-crystallization" tabindex="-1">E.3. Fractional crystallization <a class="header-anchor" href="#E.3.-Fractional-crystallization" aria-label="Permalink to &quot;E.3. Fractional crystallization {#E.3.-Fractional-crystallization}&quot;">​</a></h3><p>Let us the same database and bulk rock composition as for the fractional melting example. Simply change the path definition as follow:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_FC_path.png?raw=true" alt="PTX FC path" style="max-width:80%;height:auto;display:block;margin:0 auto;"><p>In the <code>Path options</code> panel, choose a resolution of 32, and select <code>P-T-X mode = fractional crystallization</code>, keep <code>Assimiliation = false</code> and <code>Remaining fraction [%] = 1</code>:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_FC_path_mode.png?raw=true" alt="PTX FC path mode" style="max-width:40%;height:auto;display:block;margin:0 auto;"><div class="tip custom-block"><p class="custom-block-title">Note</p><ul><li><code>Remaining fraction [%]</code> can be thought as a small fraction of the solid rock carried by the fractionating melt.</li></ul></div><p>Process with the P-T-X path calculation, which should yield:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_FC_path_diagram.png?raw=true" alt="PTX FC path diagram" style="max-width:80%;height:auto;display:block;margin:0 auto;"><p>and <code>TAS diagram</code> (Total Alkali Silica):</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_FC_path_TAS.png?raw=true" alt="PTX path TAS" style="max-width:60%;height:auto;display:block;margin:0 auto;"><div class="tip custom-block"><p class="custom-block-title">Note</p><ul><li>The size of the circle symbol in the TAS diagram scales with the <code>remaining %</code>. This gives an idea of the volume of generated magma along the fractional crystallization path.</li></ul></div><h3 id="E.4.-Assimilation" tabindex="-1">E.4. Assimilation <a class="header-anchor" href="#E.4.-Assimilation" aria-label="Permalink to &quot;E.4. Assimilation {#E.4.-Assimilation}&quot;">​</a></h3><p>In this example we are going to compute an equilibrium batch crystallization path of a wet basalt, and, progressive assimilation of tonalitic composition. Let&#39;s first select the <code>Igneous</code> database (Green et al., 2025, after Holland et al., 2018) and define the P-T path as follow:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_assimilation_path.png?raw=true" alt="PTX assimilation path" style="max-width:60%;height:auto;display:block;margin:0 auto;"><div class="tip custom-block"><p class="custom-block-title">Note</p><ul><li>Notice the new column in the P-T path definition <code>Add [mol%]</code>. Here you can define how much of the assimilated composition will be added for each P-T step.</li></ul></div><p>In <code>Path options</code>, set <code>Resolution = 32</code>, <code>P-T-X mode = Equilibrium</code> and <code>Assimilatiom = true</code>. When <code>Assimilatiom = true</code> a second bulk-rock composition is available for selection in the <code>Bulk-rock composition</code>left panel. Choose <code>Wet basalt</code> for the left (starting) composition and <code>Tonalite 101</code> for the right (assimilated) composition:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_assimilation_path_compo.png?raw=true" alt="PTX assimilation path compo" style="max-width:40%;height:auto;display:block;margin:0 auto;"><p>Performing the calculation of the P-T path gives:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_assimilation_diagram.png?raw=true" alt="PTX assimilation diagram" style="max-width:80%;height:auto;display:block;margin:0 auto;"><p>and the following TAS diagram:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_assimilation_TAS.png?raw=true" alt="PTX assimilation TAS" style="max-width:80%;height:auto;display:block;margin:0 auto;"><h3 id="E.5.-Variable-buffer" tabindex="-1">E.5. Variable buffer <a class="header-anchor" href="#E.5.-Variable-buffer" aria-label="Permalink to &quot;E.5. Variable buffer {#E.5.-Variable-buffer}&quot;">​</a></h3><p>To simulate a change in oxydation/reduction state of the system you can also provide variable buffer offsets. Let&#39;s start from previous assimilation example 4, and select <code>Buffer = QFM</code> and <code>Variable buffer = true</code> in the <code>Configuration</code> panel.</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_var_buffer_path_selec.png?raw=true" alt="PTX var buffer path" style="max-width:40%;height:auto;display:block;margin:0 auto;"><p>A new column named <code>Buffer</code> is now available in the <code>Path definition</code> panel and you can modify the buffer offset to your liking. For instance:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_var_buffer_path.png?raw=true" alt="PTX var buffer path" style="max-width:40%;height:auto;display:block;margin:0 auto;"><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Don&#39;t forget to oversaturate the <code>O</code> content of the bulk-rock compositions.</p></div><p>Performing the calculation of the P-T path gives:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_var_buffer_diagram.png?raw=true" alt="PTX variable buffer diagram" style="max-width:80%;height:auto;display:block;margin:0 auto;"><p>and the following TAS diagram:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_var_buffer_TAS.png?raw=true" alt="PTX variable buffer TAS" style="max-width:80%;height:auto;display:block;margin:0 auto;"><h2 id="Isentropic-path-MAGEMinApp-v1.2.1" tabindex="-1">Isentropic path (MAGEMinApp v1.2.1) <a class="header-anchor" href="#Isentropic-path-MAGEMinApp-v1.2.1" aria-label="Permalink to &quot;Isentropic path (MAGEMinApp v1.2.1) {#Isentropic-path-MAGEMinApp-v1.2.1}&quot;">​</a></h2><p>Isentropic path typically represent a process where a rock or material undergoes changes in pressure and temperature without any exchange of heat with its surroundings (adiabatic process) and without any entropy production (reversible process). This type of path is often used to model processes like mantle convection or adiabatic decompression melting, where material moves through the Earth&#39;s interior under conditions that approximate constant entropy.</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>The isentropic tab was removed in <code>MAGEMinApp@1.2.1</code> and merged with PTX path tab. This allowed to use the PTX functionality such as fractional crystallization and assimilation</p></div><h3 id="E.6.-Isentropic-path-constant-bulk" tabindex="-1">E.6. Isentropic path - constant bulk <a class="header-anchor" href="#E.6.-Isentropic-path-constant-bulk" aria-label="Permalink to &quot;E.6. Isentropic path - constant bulk {#E.6.-Isentropic-path-constant-bulk}&quot;">​</a></h3><p>Isentropic paths are easy to setup. Simply launch <code>MAGEMinApp</code> and navigate to the <code>PTX path</code> tab. Change to thermodynamic database (<code>Metapelite</code>)(White et al., 2014) and default bulk-rock composition. In the <code>Path options</code> panel, select <code>Isentropic = true</code> and keep all other parameters by default:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_isoS_path_opt.png?raw=true" alt="isoS path setup" style="max-width:44%;height:auto;display:block;margin:0 auto;"><p>Notice here that for isentropic path only the starting temperature and pressure can be changed. Then simply click <code>Compute path</code>:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_isoS_path_res.png?raw=true" alt="isoS path diagram" style="max-width:80%;height:auto;display:block;margin:0 auto;"><div class="tip custom-block"><p class="custom-block-title">Note</p><ul><li><p>Here we use a bisection method to ensure constant entropy within a temperature tolerance</p></li><li><p>In the top-right panel (<code>Path preview</code> ) you can retrieve information about the entropy value in <code>J/K</code> and the isentropic pressure-temperature path.</p></li></ul><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_isoS_path_preview.png?raw=true" alt="isoS path info" style="max-width:75%;height:auto;display:block;margin:0 auto;"></div><h3 id="E.7.-isentropic-fractional-crystallization" tabindex="-1">E.7. isentropic fractional crystallization <a class="header-anchor" href="#E.7.-isentropic-fractional-crystallization" aria-label="Permalink to &quot;E.7. isentropic fractional crystallization {#E.7.-isentropic-fractional-crystallization}&quot;">​</a></h3><p>Building upon previous example, you can use the fractional crystallization mode along with the isentropic option:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_isoS_path_opt_FC.png?raw=true" alt="isoS path setup FC" style="max-width:44%;height:auto;display:block;margin:0 auto;"><p>Computing the path will generate two diagrams: the stable phase fractions and fractionated phases.</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_isoS_path_opt_FC_res.png?raw=true" alt="isoS path diagram" style="max-width:80%;height:auto;display:block;margin:0 auto;"><h3 id="E.8.-isentropic-fractional-crystallization-with-assimilation" tabindex="-1">E.8. isentropic fractional crystallization with assimilation <a class="header-anchor" href="#E.8.-isentropic-fractional-crystallization-with-assimilation" aria-label="Permalink to &quot;E.8. isentropic fractional crystallization with assimilation {#E.8.-isentropic-fractional-crystallization-with-assimilation}&quot;">​</a></h3><p>One can also compute isentropic crystallization paths with assimilation of a secondary bulk-rock composition (host-rock, second magma etc.)</p><p>First activate the <code>Assimilation</code> option. Then, in the <code>Path definition</code> panel, you can see that next to pressure a new column appears which allows you to add fraction of the second bulk-rock composition in mol%. Modify the entry for the second point to 50%:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_isoS_path_opt_FCA.png?raw=true" alt="isoS path setup FC" style="max-width:60%;height:auto;display:block;margin:0 auto;"><div class="tip custom-block"><p class="custom-block-title">Note</p><ul><li><p>If you put a non zero value for the first row of the <code>Add [mol%]</code> column this will change the starting bulk-rock composition accordingly</p></li><li><p>When changing any other rows, the <code>Add [mol%]</code> will be added progressively from the previous point</p></li></ul></div><p>You can now change the second bulk-rock compositon available in the left <code>Bulk-rock composition</code> panel. For instance:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_isoS_path_opt_FCA_bulk.png?raw=true" alt="isoS path setup FC bulk" style="max-width:44%;height:auto;display:block;margin:0 auto;"><p>Compute the path:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_isoS_path_opt_FCA_res.png?raw=true" alt="isoS path diagram with assimilation" style="max-width:80%;height:auto;display:block;margin:0 auto;"><h2 id="Modify-colormap-MAGEMinApp-v1.2.1" tabindex="-1">Modify colormap (MAGEMinApp v1.2.1) <a class="header-anchor" href="#Modify-colormap-MAGEMinApp-v1.2.1" aria-label="Permalink to &quot;Modify colormap (MAGEMinApp v1.2.1) {#Modify-colormap-MAGEMinApp-v1.2.1}&quot;">​</a></h2><p>Since version 1.2.0 it is possible to adjust the colormap of the area plots. In the <code>Display options</code> panel on the right, click on <code>Modify phase colors</code>:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_colormap_select.png?raw=true" alt="colormap select" style="max-width:44%;height:auto;display:block;margin:0 auto;"><p>This unfold a window a the left of your screen where the colors of all stable phases are displayed:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_colormap.png?raw=true" alt="colormap" style="max-width:44%;height:auto;display:block;margin:0 auto;"><p>To modify a color, click the corresponding cell in the Change column, then change the thin colored bar on the right. This option the color picker:</p><img src="https://raw.githubusercontent.com/ComputationalThermodynamics/repositories_pictures/main/MAGEMin_doc/v1.2.1_MAGEMinApp_PTX_color_pick.png?raw=true" alt="color_pick" style="max-width:70%;height:auto;display:block;margin:0 auto;"><div class="tip custom-block"><p class="custom-block-title">Note</p><ul><li><p>Only the phases stable in your calculation can be modified</p></li><li><p>Once your happy with the updated colors, to apply the changes, you need to redo the PTX path calculation</p></li><li><p>You can save your changes by clicking on the green button <code>Save colors/styles</code>. The changes are saved even when restarting the App.</p></li></ul></div><h2 id="Trace-element-partitioning-MAGEMinApp-v1.5.1" tabindex="-1">Trace-element partitioning (MAGEMinApp v1.5.1) <a class="header-anchor" href="#Trace-element-partitioning-MAGEMinApp-v1.5.1" aria-label="Permalink to &quot;Trace-element partitioning (MAGEMinApp v1.5.1) {#Trace-element-partitioning-MAGEMinApp-v1.5.1}&quot;">​</a></h2><p>Trace-element (TE) partitioning can be computed simultaneously with any P-T-X path (batch melting, fractional melting, fractional crystallization, isentropic). The module uses lattice-strain parameterized Kd databases and optionally applies mineral or volatile saturation models (Zr, S, P₂O₅, CO₂).</p><h3 id="E.9.-Trace-element-partitioning-setup" tabindex="-1">E.9. Trace-element partitioning setup <a class="header-anchor" href="#E.9.-Trace-element-partitioning-setup" aria-label="Permalink to &quot;E.9. Trace-element partitioning setup {#E.9.-Trace-element-partitioning-setup}&quot;">​</a></h3><h4 id="Step-1-—-Activate-the-TE-predictive-model" tabindex="-1">Step 1 — Activate the TE predictive model <a class="header-anchor" href="#Step-1-—-Activate-the-TE-predictive-model" aria-label="Permalink to &quot;Step 1 — Activate the TE predictive model {#Step-1-—-Activate-the-TE-predictive-model}&quot;">​</a></h4><p>In the <code>Path options</code> panel, set <code>TE predictive model = true</code>. This reveals the <code>Trace Elements</code> panel in the left sidebar.</p><h4 id="Step-2-—-Configure-KD-model-and-saturation-options" tabindex="-1">Step 2 — Configure KD model and saturation options <a class="header-anchor" href="#Step-2-—-Configure-KD-model-and-saturation-options" aria-label="Permalink to &quot;Step 2 — Configure KD model and saturation options {#Step-2-—-Configure-KD-model-and-saturation-options}&quot;">​</a></h4><p>In the <code>Trace Elements</code> panel, the following options are available:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Option</th><th style="text-align:right;">Description</th><th style="text-align:right;">Available values</th></tr></thead><tbody><tr><td style="text-align:right;"><strong>KD model</strong></td><td style="text-align:right;">Lattice-strain Kd database</td><td style="text-align:right;"><code>OL</code> — O. Laurent (2012) ; <code>CO</code> — J. Cornet (2019)</td></tr><tr><td style="text-align:right;"><strong>Zr saturation</strong></td><td style="text-align:right;">Zircon saturation model</td><td style="text-align:right;"><code>none</code> ; <code>Watson 1979</code> (WH) ; <code>Blundy 2022</code> (CB)</td></tr><tr><td style="text-align:right;"><strong>S saturation</strong></td><td style="text-align:right;">Sulfide saturation model</td><td style="text-align:right;"><code>none</code> ; <code>Liu 2021</code> (Liu07)</td></tr><tr><td style="text-align:right;"><strong>P₂O₅ saturation</strong></td><td style="text-align:right;">Fluorapatite saturation model</td><td style="text-align:right;"><code>none</code> ; <code>Tollari 2006</code></td></tr><tr><td style="text-align:right;"><strong>CO₂ saturation</strong></td><td style="text-align:right;">CO₂ fluid saturation model</td><td style="text-align:right;"><code>none</code> ; <code>SY26</code> — Sun &amp; Yao (2026)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Note</p><ul><li><p>Saturation models only activate when the corresponding element is present in the TE bulk composition.</p></li><li><p>The CO₂ saturation model (SY26) requires dissolved H₂O in the melt: it inverts the H₂O solubility equation to derive P_H₂O, then evaluates CO₂ solubility at P_CO₂ = P − P_H₂O.</p></li></ul></div><h4 id="Step-3-—-Load-the-trace-element-bulk-composition" tabindex="-1">Step 3 — Load the trace-element bulk composition <a class="header-anchor" href="#Step-3-—-Load-the-trace-element-bulk-composition" aria-label="Permalink to &quot;Step 3 — Load the trace-element bulk composition {#Step-3-—-Load-the-trace-element-bulk-composition}&quot;">​</a></h4><p>Two options are available:</p><ul><li><p><strong>Built-in database</strong>: use the dropdown below the saturation options to select a predefined TE composition; the <code>Initial TE bulk composition [μg/g]</code> table updates automatically.</p></li><li><p><strong>Custom file</strong>: drag and drop a CSV file onto the upload area. The file must contain <code>element</code> and <code>μg/g</code> columns.</p></li></ul><p>Values in the table are editable directly in the interface.</p><p>When <code>Assimilation = true</code>, a second table (<code>Assimilant TE bulk composition [μg/g]</code>) is also displayed and follows the same loading logic.</p><h4 id="Step-4-—-Compute-the-path" tabindex="-1">Step 4 — Compute the path <a class="header-anchor" href="#Step-4-—-Compute-the-path" aria-label="Permalink to &quot;Step 4 — Compute the path {#Step-4-—-Compute-the-path}&quot;">​</a></h4><p>Click <code>Compute path</code>. Thermodynamic minimization and TE partitioning are performed simultaneously at each step along the path.</p><h3 id="E.10.-Visualizing-trace-element-results" tabindex="-1">E.10. Visualizing trace-element results <a class="header-anchor" href="#E.10.-Visualizing-trace-element-results" aria-label="Permalink to &quot;E.10. Visualizing trace-element results {#E.10.-Visualizing-trace-element-results}&quot;">​</a></h3><p>After computation, the <code>Trace Elements</code> tab becomes enabled. It contains:</p><ul><li><p><strong>REE spectrum</strong> (top panel): rare-earth element pattern at the selected path point, normalized to bulk or chondrite. Use the <code>Show</code> dropdown to switch between <code>ree</code> (REE only) and <code>all</code> (extended trace-element set).</p></li><li><p><strong>Diagram</strong> (bottom panel): P-T diagram colored by a user-selected TE or saturation field.</p></li></ul><p>In the <code>Display options</code> panel (right side) use the <code>Field type</code> dropdown to choose what to display:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Field type</th><th style="text-align:right;">Available fields</th></tr></thead><tbody><tr><td style="text-align:right;">Zircon</td><td style="text-align:right;"><code>Sat_Zr_liq</code> [ug/g] — Zr saturation in melt ; <code>zrc_wt</code> — zircon weight fraction</td></tr><tr><td style="text-align:right;">Sulfide</td><td style="text-align:right;"><code>Sat_S_liq</code> [ug/g] — S saturation in melt ; <code>sulf_wt</code> — sulfide weight fraction</td></tr><tr><td style="text-align:right;">Fluorapatite</td><td style="text-align:right;"><code>Sat_P2O5_liq</code> [ug/g] — P₂O₅ saturation in melt ; <code>fapt_wt</code> — apatite weight fraction</td></tr><tr><td style="text-align:right;">CO2 saturation</td><td style="text-align:right;"><code>Sat_CO2_liq</code> [ug/g] — CO₂ saturation in melt ; <code>fl_CO2_wt</code> — CO₂ fluid weight fraction</td></tr><tr><td style="text-align:right;">Trace element</td><td style="text-align:right;">Any TE concentration or user-defined expression (see below)</td></tr></tbody></table><p>For the <strong>Trace element</strong> field type, the <strong>Field builder</strong> allows you to enter arbitrary expressions, for example:</p><ul><li><p><code>[M_Dy] / [M_Yb]</code> — Dy/Yb ratio in the melt</p></li><li><p><code>[M_La] / [M_Sm]</code> — La/Sm ratio</p></li></ul><p>where <code>[M_X]</code> refers to element X in the melt. Set a normalization (<code>none</code>, <code>bulk</code>, <code>chondrite</code>) and click <code>Compute and display</code>.</p><p>Isopleths (contour lines) for any field can be added from the <code>Isopleths</code> tab: select the field type and field, set the range and step, and click <code>Add</code>.</p><h3 id="E.11.-Exporting-trace-element-results-to-CSV" tabindex="-1">E.11. Exporting trace-element results to CSV <a class="header-anchor" href="#E.11.-Exporting-trace-element-results-to-CSV" aria-label="Permalink to &quot;E.11. Exporting trace-element results to CSV {#E.11.-Exporting-trace-element-results-to-CSV}&quot;">​</a></h3><p>When <code>TE predictive model = true</code>, additional export buttons appear in the <code>Path options</code> panel:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Button</th><th style="text-align:right;">Filename field</th><th style="text-align:right;">Content</th></tr></thead><tbody><tr><td style="text-align:right;"><strong>Save path</strong> → <code>csv</code></td><td style="text-align:right;"><code>Save path</code> input</td><td style="text-align:right;">Full PTX path: P, T, phase fractions and oxide compositions at each step (one row per step)</td></tr><tr><td style="text-align:right;"><strong>Save path</strong> → <code>csv line</code></td><td style="text-align:right;"><code>Save path</code> input</td><td style="text-align:right;">Same content but all steps written on a single row (useful for batch processing)</td></tr><tr><td style="text-align:right;"><strong>Save cumulate</strong> → <code>csv file</code></td><td style="text-align:right;"><code>Save cumulate</code> input</td><td style="text-align:right;">Cumulate (extracted solid) composition along the path</td></tr><tr><td style="text-align:right;"><strong>Save trace elements</strong> → <code>csv file</code></td><td style="text-align:right;"><code>Save trace elements</code> input</td><td style="text-align:right;">TE concentrations in the melt, bulk solid and individual mineral phases at each step</td></tr><tr><td style="text-align:right;"><strong>Save cumulate TE</strong> → <code>csv file</code></td><td style="text-align:right;"><code>Save cumulate TE</code> input</td><td style="text-align:right;">Integrated cumulate TE composition at each step</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Note</p><ul><li><p><code>Save trace elements</code> and <code>Save cumulate TE</code> are only active after trace elements have been computed. A warning badge is shown if you try to export beforehand.</p></li><li><p>All CSV files are saved to the <code>output/</code> subdirectory of the working directory displayed in the Julia terminal.</p></li></ul></div><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Use the <code>Export references → bibtex file</code> button to export a BibTeX file listing all references for the active KD model, saturation models and thermodynamic database.</p></div>',119)])])}const m=e(n,[["render",l]]);export{u as __pageData,m as default};
